const headerMap = {
  'Work Order ID': 'workOrderId',
  'Submitted At': 'submittedAt',
  'Organization': 'locationGroup',
  'Location': 'locationSub',
  'Requested By': 'requesterName',
  'Contact Method': 'contactMethod',
  'Category': 'category',
  'Priority': 'priority',
  'Safety Hazard': 'safetyHazard',
  'Description': 'description',
  'Best Time to Access': 'bestTimeToAccess',
  'Needed By Date': 'neededByDate',
  'Photo Count': 'photoCount',
  'Photo URLs': 'photoUrls',
  'PDF URL': 'pdfUrl',
  'Status': 'status',
  'Technician': 'techName',
  'Closed At': 'closedAt',
  'Completion Notes': 'completionNotes',
  'Parts Used': 'partsUsed',
  'Completion Photo URL': 'completionPhotoUrl',
  'Closure PDF URL': 'closurePdfUrl'
};

const rows = $input.all();
if (!rows || rows.length === 0) {
  return [{ json: { data: [] } }];
}

const data = rows
  .map(item => {
    const mapped = {};
    for (const [sheetCol, jsonKey] of Object.entries(headerMap)) {
      mapped[jsonKey] = item.json[sheetCol] || '';
    }
    return mapped;
  })
  .filter(row => row.workOrderId);

return [{ json: { data } }];
